import re

file_path = r'C:\Users\nitin\Documents\antigravity\mysterious-volta\index.html'

with open(file_path, 'r', encoding='utf-8') as f:
    content = f.read()

# 1. Replace the long inline style with class="callout-tip"
inline_style_pattern = r'style="background: rgba\(14, 116, 144, 0\.05\); border-color: var\(--primary-blue\); font-size: 0\.85rem; color: var\(--primary-navy\);( line-height: 1\.4;)?"'
content = re.sub(r'class="([^"]+)"\s+' + inline_style_pattern, r'class="\1 callout-tip"', content)

# 2. Replace the icon wrappers in the hero section to prevent FOUC
icons = {
    'PieChart': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-pie-chart"><path d="M21.21 15.89A10 10 0 1 1 8 2.83"/><path d="M22 12A10 10 0 0 0 12 2v10z"/></svg>',
    'Shield': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-shield"><path d="M20 13c0 5-3.5 7.5-7.66 8.95a1 1 0 0 1-.67-.01C7.5 20.5 4 18 4 13V6a1 1 0 0 1 1-1c2 0 4.5-1.2 6.24-2.72a1.17 1.17 0 0 1 1.52 0C14.51 3.81 17 5 19 5a1 1 0 0 1 1 1z"/></svg>',
    'Target': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-target"><circle cx="12" cy="12" r="10"/><circle cx="12" cy="12" r="6"/><circle cx="12" cy="12" r="2"/></svg>',
    'Scale': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-scale"><path d="m16 16 3-8 3 8c-.87.65-1.92 1-3 1s-2.13-.35-3-1Z"/><path d="m2 16 3-8 3 8c-.87.65-1.92 1-3 1s-2.13-.35-3-1Z"/><path d="M7 21h10"/><path d="M12 3v18"/><path d="M3 7h2c2 0 5-1 7-2 2 1 5 2 7 2h2"/></svg>',
    'TrendingUp': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-trending-up"><polyline points="22 7 13.5 15.5 8.5 10.5 2 17"/><polyline points="16 7 22 7 22 13"/></svg>',
    'Building': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-building"><rect width="16" height="20" x="4" y="2" rx="2" ry="2"/><path d="M9 22v-4h6v4"/><path d="M8 6h.01"/><path d="M16 6h.01"/><path d="M12 6h.01"/><path d="M12 10h.01"/><path d="M12 14h.01"/><path d="M16 10h.01"/><path d="M16 14h.01"/><path d="M8 10h.01"/><path d="M8 14h.01"/></svg>',
    'Coins': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-coins"><circle cx="8" cy="8" r="6"/><path d="M18.09 10.37A6 6 0 1 1 10.34 18"/><path d="M7 6h1v4"/><path d="M16.71 13.88l-1.42 1.42"/></svg>',
    'Wallet': '<svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="lucide lucide-wallet"><path d="M19 7V4a1 1 0 0 0-1-1H5a2 2 0 0 0 0 4h15a1 1 0 0 1 1 1v4h-3a2 2 0 0 0 0 4h3a1 1 0 0 0 1-1v-2a1 1 0 0 0-1-1"/><path d="M3 5v14a2 2 0 0 0 2 2h15a1 1 0 0 0 1-1v-4"/></svg>'
}
for name, svg in icons.items():
    content = content.replace(f'<div class="icon-wrapper icon-primary mb-4">{name}</div>', f'<div class="icon-wrapper icon-primary mb-4">{svg}</div>')
    content = content.replace(f'<div class="icon-wrapper small text-green">{name}</div>', f'<div class="icon-wrapper small text-green">{svg}</div>')
    content = content.replace(f'<div class="icon-wrapper small text-gold">{name}</div>', f'<div class="icon-wrapper small text-gold">{svg}</div>')
    content = content.replace(f'<div class="icon-wrapper small text-blue">{name}</div>', f'<div class="icon-wrapper small text-blue">{svg}</div>')
    content = content.replace(f'<div class="icon-wrapper small text-navy">{name}</div>', f'<div class="icon-wrapper small text-navy">{svg}</div>')

# Remove the JS injection script at the bottom
injection_script_start = content.find('<!-- Icon Injection Script -->')
if injection_script_start != -1:
    injection_script_end = content.find('</script>', injection_script_start) + 9
    content = content[:injection_script_start] + content[injection_script_end:]

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(content)

print("Safe updates complete.")
